from kelvin.application import KelvinApp
    from kelvin.message.evidences import Dynacard
    from kelvin.krn import KRNAsset
    from datetime import datetime, timedelta

    app = KelvinApp()

    @app.timer(interval=10)
    async def publish_data():

        evidences = [
            Dynacard(
                title="Sample Chart Title",
                timestamp=datetime.now(),
                xAxis={
                        "title": "X-Axis Title"
                },
                yAxis={
                    "title": "Y-Axis Title"
                },
                series=[
                    {"name": "Series 1", "data": [1, 2, 3, 4, 5]},
                    {"name": "Series 2", "data": [[1, 2], [2, 3], [3, 5], [4, 7]]}
                ]
            )
        ]

        recommendation = Recommendation(
            resource=KRNAsset('pcp_51'),
            type="decrease_speed",
            control_changes=[],
            expiration_date=timedelta(hours=1),
            evidences=evidences,
        )

        await app.publish(recommendation)

    app.run()
